        if lk == 'true' or lk == 't' or lk == '1':
            true_count = int(v)
        if lk == 'false' or lk == 'f' or lk == '0':
            false_count = int(v)
    # also check exact keys 'True'/'False'
    if true_count is None and 'True' in r:
        true_count = int(r['True'])
    if false_count is None and 'False' in r:
        false_count = int(r['False'])
    # fallback: try to find any boolean-like key names
    if true_count is None:
        for k in r:
            if str(k).lower()=='true':
                true_count = int(r[k])
    if false_count is None:
        for k in r:
            if str(k).lower()=='false':
                false_count = int(r[k])
    # If still None, try keys by position: assume columns order is given in cols
    if (true_count is None or false_count is None) and len(cols)==2:
        # cols list like ['False','True']
        col0 = cols[0]
        col1 = cols[1]
        # try fetch by these names
        if true_count is None and col1 in r:
            true_count = int(r[col1])
        if false_count is None and col0 in r:
            false_count = int(r[col0])
    # If still None, skip
    if true_count is None or false_count is None:
        continue
    row_total = true_count + false_count
    selected.append({'histological_type': r.get('histological_type'), 'true': true_count, 'false': false_count, 'row_total': row_total})

# Filter rows with row_total > 10
included = [r for r in selected if r['row_total'] > 10]

if len(included) == 0:
    result = {'chi2': None, 'message': 'No histological categories with row total > 10 after filtering.'}
else:
    # Build observation matrix with order rows x [mut_yes (True), mut_no (False)]
    obs = [[r['true'], r['false']] for r in included]
    # compute totals
    grand_total = sum([sum(r) for r in obs])
    row_totals = [sum(r) for r in obs]
    col_totals = [sum(r[i] for r in obs) for i in range(2)]
    # expected
    expected = []
    for rt in row_totals:
        expected.append([rt*col_totals[0]/grand_total, rt*col_totals[1]/grand_total])
    # chi2
    chi2 = 0.0
    for i in range(len(obs)):
        for j in range(2):
            exp = expected[i][j]
            o = obs[i][j]
            if exp == 0:
                continue
            chi2 += (o - exp)**2 / exp
    # Prepare contingency dict
    contingency = {}
    for i,r in enumerate(included):
        contingency[r['histological_type']] = {'CDH1_mut_yes': int(r['true']), 'CDH1_mut_no': int(r['false']), 'row_total': int(r['row_total'])}
    col_totals_dict = {'CDH1_mut_yes': int(col_totals[0]), 'CDH1_mut_no': int(col_totals[1])}
    result = {'chi2': chi2, 'grand_total': int(grand_total), 'col_totals': col_totals_dict, 'contingency': contingency}

print("__RESULT__:")
print(json.dumps(result))
"}

